"use client";

import { useState } from "react";

export default function OrderTab({ orders }) {
    const [orderList, setOrderList] = useState(orders);

    const handleReceive = (id) => {
        setOrderList(prev => prev.filter(order => order.id !== id));
    };

    return (
        <div className="space-y-6">
            {orderList.length > 0 ? (
                orderList.map(order => (
                    <div
                        key={order.id}
                        className="flex items-start space-x-4 pb-4 border-b relative"
                    >
                        {/* จำนวนสินค้า (x1, x3) มุมขวาบน */}
                        <span className="absolute top-0 right-0 text-xs text-gray-500">
                            x{order.qty}
                        </span>

                        {/* รูปสินค้า */}
                        <img
                            src={order.image}
                            alt={order.name}
                            className="w-16 h-16 border rounded object-cover"
                        />

                        {/* รายละเอียดสินค้า */}
                        <div className="flex-1 flex flex-col justify-between">
                            <div>
                                <p className="text-sm font-medium">{order.name}</p>
                                <p className="text-xs text-gray-500">
                                    TotalProduct: {order.qty}
                                </p>
                                <div className="flex items-center space-x-2 mt-1">
                                    <p className="text-xs">
                                        Status:{" "}
                                        <span
                                            className={`font-medium ${
                                                order.status === "pending"
                                                    ? "text-green-600"
                                                    : "text-orange-500"
                                            }`}
                                        >
                                            {order.status}
                                        </span>
                                    </p>

                                    {/* ปุ่มเฉพาะ fulfilled */}
                                    {order.status === "fulfilled" && (
                                        <button
                                            onClick={() => handleReceive(order.id)}
                                            className="px-3 py-1 text-xs bg-green-600 text-white rounded"
                                        >
                                            receive
                                        </button>
                                    )}
                                </div>
                            </div>

                            {/* ราคา (มุมซ้ายล่าง) */}
                            <span className="text-sm font-semibold mt-2">
                                ${order.price}
                            </span>
                        </div>
                    </div>
                ))
            ) : (
                <div className="text-center text-gray-500 mt-10">
                    📦 No orders yet.
                </div>
            )}
        </div>
    );
}
